query:
DESCRIBE pagamentos;
SELECT tipo, descricao, valor, mesRef, chaveJ, status FROM pagamentos WHERE tipo LIKE '%diant%' OR descricao LIKE '%diant%' LIMIT 10;
SELECT DISTINCT tipo FROM pagamentos ORDER BY tipo;

